import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Star } from 'lucide-react';
import '../styles/Katalog.css';

const DetailProduk = ({ tambahKeKeranjang }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [jumlahBeli, setJumlahBeli] = useState(1);
  const [indeksGambar, setIndeksGambar] = useState(0);

  const produkList = [
    { id: 1, nama: 'Black Forest Cake', harga: 'Rp 150.000', kategori: 'Kue Ulang Tahun', img: 'https://images.unsplash.com/photo-1606890737304-57a1ca8a5b62?auto=format&fit=crop&q=80', deskripsi: 'Kue Black Forest klasik dengan bolu cokelat lembut, dilapisi krim segar dan selai ceri hitam asli. Dihiasi dengan serutan cokelat tebal dan buah ceri segar di atasnya. Ukuran: Diameter 20cm (Cocok untuk 8-10 potong).' },
    { id: 2, nama: 'Cheesecake', harga: 'Rp 85.000', kategori: 'Kue Ulang Tahun', img: 'https://images.unsplash.com/photo-1533134242443-d4fd215305ad?auto=format&fit=crop&q=80', deskripsi: 'Cheesecake panggang dengan tekstur sangat lembut dan lumer di mulut. Dibuat dari cream cheese premium pilihan dengan alas biskuit mentega yang renyah.' },
    { id: 3, nama: 'Tiramisu Dessert Box', harga: 'Rp 45.000', kategori: 'Dessert Box', img: 'https://images.unsplash.com/photo-1571115177098-24edf3e00b65?auto=format&fit=crop&q=80', deskripsi: 'Dessert box tiramisu khas Italia dengan lapisan lady finger yang direndam kopi espresso murni, dipadukan dengan krim mascarpone tebal dan taburan bubuk kakao.' },
    { id: 4, nama: 'Nastar Keju Premium', harga: 'Rp 120.000', kategori: 'Kue Kering', img: 'https://images.unsplash.com/photo-1605335967732-2b6389fccb8c?auto=format&fit=crop&q=80', deskripsi: 'Kue kering nastar dengan isian selai nanas asli yang melimpah. Adonan kulitnya dicampur dengan keju edam sehingga menghasilkan perpaduan rasa manis dan gurih.' },
    { id: 5, nama: 'Red Velvet Cake', harga: 'Rp 140.000', kategori: 'Kue Ulang Tahun', img: 'https://images.unsplash.com/photo-1616541823729-00fe0aacd32c?auto=format&fit=crop&q=80', deskripsi: 'Bolu Red Velvet berlapis dengan olesan cream cheese frosting yang melimpah dan tidak eneg. Memiliki warna merah merona yang menggugah selera.' },
    { id: 6, nama: 'Bolu Cukke\'', harga: 'Rp 60.000', kategori: 'Kue Kering', img: 'https://images.unsplash.com/photo-1587241321921-91a834d6d191?auto=format&fit=crop&q=80', deskripsi: 'Bolu Cukke tradisional khas daerah dengan bahan dasar gula merah murni pilihan. Memiliki tekstur padat namun lembut saat digigit, sangat cocok untuk teman minum teh.' }
  ];

  // Mengubah ID dari URL menjadi angka agar bisa dicocokkan dengan data
  const produk = produkList.find(p => p.id === parseInt(id));
  const stokTersedia = 15;

  // PENCEGAH LAYAR BLANK: Jika produk tidak ditemukan, tampilkan pesan ini
  if (!produk) {
    return (
      <div className="katalog-wrapper" style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh' }}>
        <div style={{ background: 'white', padding: '40px', borderRadius: '12px', textAlign: 'center', zIndex: 10 }}>
          <h2>Oops! Produk Tidak Ditemukan</h2>
          <p>Sepertinya terjadi kesalahan saat memuat data kue.</p>
          <button onClick={() => navigate('/')} style={{ padding: '10px 20px', background: '#b45309', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer', marginTop: '15px' }}>
            Kembali ke Katalog Utama
          </button>
        </div>
      </div>
    );
  }

  // Galeri gambar (Gambar pertama adalah gambar asli produk, sisanya variasi agar terlihat efek kliknya)
  const galeri = [
    produk.img,
    'https://images.unsplash.com/photo-1578985545062-69928b1d9587?auto=format&fit=crop&q=80',
    'https://images.unsplash.com/photo-1588195538326-c5b1e9f80a1b?auto=format&fit=crop&q=80',
    'https://images.unsplash.com/photo-1557925923-cd4648e211a0?auto=format&fit=crop&q=80'
  ];

  const aturJumlah = (angka) => {
    const nilaiBaru = jumlahBeli + angka;
    if (nilaiBaru >= 1 && nilaiBaru <= stokTersedia) {
      setJumlahBeli(nilaiBaru);
    }
  };

  const handleTambah = () => {
    tambahKeKeranjang(produk, jumlahBeli);
    navigate('/keranjang'); 
  };

  return (
    <div className="katalog-wrapper">
      <div className="katalog-overlay"></div>
      
      <div className="katalog-content" style={{ flexDirection: 'column', gap: '15px' }}>
        <div style={{ fontSize: '13px', color: '#e5e7eb', paddingLeft: '5px' }}>
          Beranda / {produk.kategori} / {produk.nama}
        </div>

        <div style={{ display: 'flex', background: 'white', borderRadius: '12px', overflow: 'hidden', width: '100%', padding: '35px', gap: '40px', boxShadow: '0 10px 25px rgba(0,0,0,0.15)' }}>
          
          {/* BAGIAN KIRI: FOTO UTAMA & THUMBNAIL */}
          <div style={{ flex: '1', display: 'flex', flexDirection: 'column', gap: '15px' }}>
            
            {/* Foto Utama yang akan berubah sesuai klik */}
            <img 
              src={galeri[indeksGambar]} 
              alt={produk.nama} 
              style={{ width: '100%', height: '380px', objectFit: 'cover', borderRadius: '8px', transition: 'all 0.3s ease' }} 
            />
            
            {/* 4 Foto Kecil (Thumbnail) */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '10px' }}>
              {galeri.map((gbr, idx) => (
                <img 
                  key={idx}
                  src={gbr} 
                  alt={`thumbnail-${idx}`} 
                  onClick={() => setIndeksGambar(idx)} // Ini adalah fungsi yang mengganti gambar utama
                  style={{ 
                    width: '100%', 
                    height: '85px', 
                    objectFit: 'cover', 
                    borderRadius: '6px', 
                    cursor: 'pointer',
                    border: indeksGambar === idx ? '2px solid #b45309' : '2px solid transparent', // Bingkai oranye jika aktif
                    opacity: indeksGambar === idx ? '1' : '0.6', // Terang jika aktif, agak buram jika tidak
                    transition: 'all 0.2s ease'
                  }} 
                />
              ))}
            </div>
          </div>

          {/* BAGIAN KANAN: INFORMASI & TOMBOL */}
          <div style={{ flex: '1', display: 'flex', flexDirection: 'column' }}>
            <h1 style={{ margin: '0 0 10px 0', fontSize: '28px', color: '#111' }}>{produk.nama}</h1>
            <h2 style={{ margin: '0 0 15px 0', fontSize: '24px', color: '#111' }}>{produk.harga}</h2>
            
            <div style={{ display: 'flex', gap: '3px', marginBottom: '30px' }}>
              {[...Array(5)].map((_, i) => (
                <Star key={i} size={18} fill="#f59e0b" color="#f59e0b" />
              ))}
            </div>

            <div style={{ borderTop: '1px solid #f3f4f6', paddingTop: '25px', marginBottom: '30px' }}>
              <h4 style={{ margin: '0 0 12px 0', fontSize: '15px', color: '#374151', fontWeight: 'bold' }}>Deskripsi Produk</h4>
              <p style={{ margin: '0', fontSize: '14px', color: '#4b5563', lineHeight: '1.7' }}>
                {produk.deskripsi}
              </p>
            </div>

            <div style={{ borderTop: '1px solid #f3f4f6', paddingTop: '25px', marginTop: 'auto' }}>
              <h4 style={{ margin: '0 0 15px 0', fontSize: '14px', color: '#374151', fontWeight: 'bold' }}>Atur Jumlah</h4>
              <div style={{ display: 'flex', alignItems: 'center', gap: '20px', marginBottom: '25px' }}>
                
                <div style={{ display: 'flex', alignItems: 'center', border: '1px solid #d1d5db', borderRadius: '6px', overflow: 'hidden', height: '40px' }}>
                  <button onClick={() => aturJumlah(-1)} style={{ width: '40px', height: '100%', background: 'white', border: 'none', borderRight: '1px solid #d1d5db', cursor: 'pointer', fontSize: '20px', color: '#374151', display: 'flex', justifyContent: 'center', alignItems: 'center' }}>-</button>
                  <span style={{ width: '60px', textAlign: 'center', fontSize: '16px', fontWeight: 'bold', color: '#111' }}>{jumlahBeli}</span>
                  <button onClick={() => aturJumlah(1)} style={{ width: '40px', height: '100%', background: 'white', border: 'none', borderLeft: '1px solid #d1d5db', cursor: 'pointer', fontSize: '20px', color: '#374151', display: 'flex', justifyContent: 'center', alignItems: 'center' }}>+</button>
                </div>
                
                <span style={{ fontSize: '13px', color: '#6b7280' }}>Stok tersedia: {stokTersedia}</span>
              </div>

              <button 
                onClick={handleTambah}
                style={{ width: '100%', padding: '16px', background: '#b45309', color: 'white', border: 'none', borderRadius: '8px', fontSize: '15px', fontWeight: 'bold', cursor: 'pointer', transition: 'background 0.3s' }}
              >
                + Masukkan Keranjang
              </button>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
};

export default DetailProduk;
